const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// Store API keys directly for development environment as requested
// IMPORTANT: For production, use Azure Key Vault references or Application Settings.
const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token_here'; // <-- IMPORTANT: You need to provide your Twilio Auth Token
const TWILIO_PHONE_NUMBER = '+1YOURTWILIONUMBER'; // <-- IMPORTANT: Your Twilio phone number (e.g., +1234567890)

// Initialize SendGrid
sgMail.setApiKey(SENDGRID_API_KEY);

// Initialize Twilio
const twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

module.exports = async function (context, req) {
    context.log('HTTP trigger function processed a request.');

    const { toEmail, fromEmail, subject, emailText, toSms, smsBody } = req.body || {};

    let responseMessages = [];
    let statusCode = 200;

    // --- Send Email via SendGrid ---
    if (toEmail && fromEmail && subject && emailText) {
        const msg = {
            to: toEmail,
            from: fromEmail, // Must be a verified sender in SendGrid
            subject: subject,
            text: emailText,
            html: `<strong>${emailText}</strong>`, // Optional: HTML content
        };

        try {
            await sgMail.send(msg);
            responseMessages.push(`Email sent to ${toEmail} successfully.`);
            context.log(`Email sent to ${toEmail}`);
        } catch (error) {
            context.error('Error sending email:', error.response ? error.response.body : error);
            responseMessages.push(`Failed to send email to ${toEmail}. Error: ${error.message || 'Unknown SendGrid error'}`);
            statusCode = 500;
        }
    } else if (req.body && (req.body.toEmail || req.body.fromEmail || req.body.subject || req.body.emailText)) {
        responseMessages.push('Missing required parameters for SendGrid email. Need toEmail, fromEmail, subject, emailText.');
        statusCode = statusCode === 200 ? 400 : statusCode;
    }

    // --- Send SMS via Twilio ---
    if (toSms && smsBody && TWILIO_AUTH_TOKEN !== 'your_twilio_auth_token_here' && TWILIO_PHONE_NUMBER !== '+1YOURTWILIONUMBER') {
        try {
            const message = await twilioClient.messages.create({
                body: smsBody,
                to: toSms,
                from: TWILIO_PHONE_NUMBER
            });
            responseMessages.push(`SMS sent to ${toSms} successfully. SID: ${message.sid}`);
            context.log(`SMS sent to ${toSms}. SID: ${message.sid}`);
        } catch (error) {
            context.error('Error sending SMS:', error);
            responseMessages.push(`Failed to send SMS to ${toSms}. Error: ${error.message || 'Unknown Twilio error'}`);
            statusCode = 500;
        }
    } else if (req.body && (req.body.toSms || req.body.smsBody)) {
        let smsErrorMessage = 'Missing required parameters for Twilio SMS. Need toSms, smsBody.';
        if (TWILIO_AUTH_TOKEN === 'your_twilio_auth_token_here') {
            smsErrorMessage += ' Also, TWILIO_AUTH_TOKEN is not configured.';
        }
        if (TWILIO_PHONE_NUMBER === '+1YOURTWILIONUMBER') {
            smsErrorMessage += ' Also, TWILIO_PHONE_NUMBER is not configured.';
        }
        responseMessages.push(smsErrorMessage);
        statusCode = statusCode === 200 ? 400 : statusCode;
    }

    // --- Respond to HTTP request ---
    if (responseMessages.length === 0) {
        statusCode = 400;
        responseMessages.push('No valid email or SMS parameters provided in the request body.');
    }

    context.res = {
        status: statusCode,
        body: responseMessages.join('\n')
    };
};